import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import Header from '../components/common/Header';
import Navbar from '../components/common/Navbar';
import Footer from '../components/common/Footer';
import ProductCard from '../components/product/ProductCard';

const Home = () => {
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  
  // Base API URL
  const API_BASE_URL = 'http://localhost:5000/api';
  
  useEffect(() => {
    fetchData();
  }, []);
  
  const fetchData = async () => {
    try {
      setLoading(true);
      
      // Lấy danh sách sản phẩm nổi bật
      const response = await axios.get(`${API_BASE_URL}/products?limit=6`);
      
      if (response.data && response.data.products) {
        setFeaturedProducts(response.data.products);
      }
      
      setLoading(false);
    } catch (error) {
      console.error('Error fetching data:', error);
      setError('Không thể tải dữ liệu. Vui lòng thử lại sau.');
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col min-h-screen">
      <Header />
      <Navbar />
      
      <main className="flex-1">
        {error && (
          <div className="bg-red-100 text-red-700 p-4 rounded m-4 max-w-7xl mx-auto">
            <div className="flex justify-between items-center">
              <span>{error}</span>
              <button 
                onClick={fetchData}
                className="bg-red-600 text-white px-4 py-2 rounded hover:bg-red-700"
              >
                Thử lại
              </button>
            </div>
          </div>
        )}
        
       {/* Hero Banner Section */}
<section className="promo-banner flex flex-col md:flex-row justify-between gap-6 my-10 mx-4 max-w-7xl xl:mx-auto">
  {/* Banner 1 */}
  <div className="relative w-full md:w-1/2 group overflow-hidden rounded-xl shadow-lg">
    <img 
      src="https://i.pinimg.com/736x/73/5c/e5/735ce5fb4b5ee2f429f1918fad3e7c1a.jpg"
      alt="Hoa tươi giảm giá"
      className="w-full h-72 md:h-96 object-cover transform group-hover:scale-105 transition duration-500"
    />
    <div className="absolute inset-0 bg-black/40 group-hover:bg-black/50 transition-all duration-500 rounded-xl"></div>
    <div className="absolute top-10 left-8 text-white">
      <h2 className="text-4xl font-bold mb-3 text-[#fff1f3]">Hoa Tươi</h2>
      <p className="text-lg mb-4">Giảm giá tới <span className="text-2xl font-bold text-[#ffccd5]">30%</span></p>
      <Link 
        to="/product"
        className="inline-block bg-[#ff8fab] py-2.5 px-5 text-white rounded-full hover:bg-[#ff6b81] transition-all duration-300"
      >
        Xem ngay
      </Link>
    </div>
  </div>

  {/* Banner 2 */}
  <div className="relative w-full md:w-1/2 group overflow-hidden rounded-xl shadow-lg">
    <img 
      src="https://shophoahong.com/wp-content/uploads/2022/06/h19-e1654479676559.jpg"
      alt="Hoa đẹp"
      className="w-full h-72 md:h-96 object-cover transform group-hover:scale-105 transition duration-500"
    />
    <div className="absolute inset-0 bg-black/40 group-hover:bg-black/50 transition-all duration-500 rounded-xl"></div>
    <div className="absolute top-10 left-8 text-white">
      <h2 className="text-3xl font-bold mb-3 text-[#fff1f3]">Hoa Đẹp</h2>
      <p className="text-lg mb-4">Giao hàng nhanh chóng</p>
      <Link 
        to="/product"
        className="inline-block bg-[#ff8fab] py-2.5 px-5 text-white rounded-full hover:bg-[#ff6b81] transition-all duration-300"
      >
        Mua ngay
      </Link>
    </div>
  </div>
</section>

        
        {/* Featured productss Section */}
        <section className="best-seller py-12 px-4 text-center max-w-7xl mx-auto">
          <div className="mb-8">
            <h2 className="text-3xl font-bold text-green-700 mb-3">
              <i className="fas fa-star text-yellow-500 mr-3"></i> 
              Top bán chạy nhất tuần
            </h2>
            <p className="text-gray-600 text-lg">Khám phá những sản phẩm được yêu thích nhất</p>
          </div>
          
          {loading ? (
            <div className="flex justify-center py-20">
              <div className="text-center">
                <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-green-700 mx-auto mb-4"></div>
                <p className="text-gray-600">Đang tải sản phẩm...</p>
              </div>
            </div>
          ) : featuredProducts.length === 0 ? (
            <div className="text-center py-20">
              <div className="text-6xl text-gray-300 mb-4">🌸</div>
              <h3 className="text-xl font-bold text-gray-600 mb-3">Chưa có sản phẩm nào</h3>
              <p className="text-gray-500 mb-6">Hãy thêm sản phẩm từ trang quản trị</p>
              <Link 
                to="/admin/products"
                className="bg-green-700 text-white px-6 py-3 rounded-lg hover:bg-green-600 transition-colors inline-block"
              >
                Đến trang quản trị
              </Link>
            </div>
          ) : (
            <div className="product-list grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
              {featuredProducts.map(product => (
                <ProductCard key={product._id} product={product} />
              ))}
            </div>
          )}
          
        
        </section>
        
        {/* Features Section */}
